<span class="line">    <span class="token keyword">print</span><span class="token punctuation">(</span>reader<span class="token punctuation">.</span>readline<span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
